def strip_html(s):
    s = re.sub(r"<at[^>]*>([^<]*)</at>", r"\1", s)
    s = re.sub(r"<[^>]+>", " ", s)
    s = html.unescape(s)
    return re.sub(r"\s+", " ", s).strip()


def sender_role(body):
    """Return 'OWNER' if the sender is Alejandro, 'GUEST' otherwise."""
    frm = body.get("from") or {}
    if frm.get("aadObjectId", "") == ALEJANDRO_AAD_ID:
        return "OWNER"
    return "GUEST"


def _bot_mentioned(body):
    """True if this bot is @-mentioned (entities walk + text fallback)."""
    for e in (body.get("entities") or []):
        if e.get("type") == "mention":
            m = e.get("mentioned") or {}
            if m.get("id", "") == BOT_FROM_ID:
                return True
    tl = (body.get("text", "") or "").lower()
    if "<at" in tl and ("alejandro's assistant" in tl or "alejandro’s assistant" in tl):
        return True
    return False


def is_actionable(body):
    """Respond to OWNER (Alejandro) anywhere, and to GUEST (anyone else)
    only in group/channel chats when this bot is @-mentioned. Personal 1:1
    chats stay owner-only."""
    if body.get("type") != "message":
        return False
    frm = body.get("from") or {}
    if frm.get("id", "") == BOT_FROM_ID:
        return False
    text = body.get("text", "") or ""
    if not text.strip():
        return False

    role = sender_role(body)
    conv = body.get("conversation", {}) or {}
    conv_type = conv.get("conversationType", "")

    # Personal 1:1 — only Alejandro.
    if conv_type == "personal":
        return role == "OWNER"
